/**
 * BTAvatarGroup — stacked group of avatars with overflow counter.
 * Sliced from Figma `Avatar Group` (node 504:705). Mirrors
 * @btech/ui-vue + btech_ui (Flutter) one-to-one.
 *
 * Stacking offsets per Figma 504:705 (negative left margin per size):
 *   xs(24)→-8, sm(32)→-10, md(40)→-12, lg(48)→-16, xl(64)→-20, 2xl(96)→-32
 *
 * ## Usage:
 * ```tsx
 * <BTAvatarGroup
 *   items={[
 *     { name: 'Person 1', imageUrl: '...' },
 *     { name: 'JD' },
 *     { name: 'AB', color: 'pink' },
 *     { name: 'XY' },
 *     { name: 'ZZ' },
 *   ]}
 *   max={3}
 *   size="md"
 * />
 * // Renders 3 avatars + "+2" overflow counter
 * ```
 */
import * as React from 'react';
import { BTAvatar } from '../avatar/BTAvatar';
import type { BTAvatarGroupProps } from './BTAvatarGroup.types';
// Import shared CSS via Avatar's stylesheet (BTAvatarGroup classes co-located)
import '../avatar/BTAvatar.css';

const cn = (...parts: Array<string | false | null | undefined>): string =>
  parts.filter(Boolean).join(' ');

export const BTAvatarGroup: React.FC<BTAvatarGroupProps> = ({
  items,
  max = 3,
  customOverflowNumber,
  size = 'md',
  isLoading = false,
  className,
}) => {
  const visible = items.slice(0, max);
  const overflowCount =
    customOverflowNumber !== undefined
      ? customOverflowNumber
      : Math.max(0, items.length - max);
  const showOverflow = overflowCount > 0;

  const groupClasses = cn(
    'btech-avatar-group',
    `btech-avatar-group--${size}`,
    className,
  );

  return (
    <div data-slot="avatar-group" className={groupClasses} role="group" aria-label="Avatar group">
      {visible.map((item, idx) => (
        <BTAvatar
          key={idx}
          item={item}
          size={size}
          isLoading={isLoading}
          className="btech-avatar-group__item"
        />
      ))}

      {showOverflow && (
        <div
          data-slot="avatar-group-count"
          className={cn('btech-avatar-group__overflow', 'btech-avatar', `btech-avatar--${size}`)}
          role="img"
          aria-label={`${overflowCount} more avatars`}
        >
          <span className="btech-avatar__count">+{overflowCount}</span>
        </div>
      )}
    </div>
  );
};

BTAvatarGroup.displayName = 'BTAvatarGroup';

/**
 * BTAvatarGroup — public API types.
 *
 * Sliced from Figma `Avatar Group` (node 504:705). Stacks BTAvatar
 * instances horizontally with negative-margin overlap. Renders an
 * overflow counter ("+N") when items.length exceeds `max`.
 */
import type {
  BTAvatarItem,
  BTAvatarSize,
} from '../avatar/BTAvatar.types';

export interface BTAvatarGroupProps {
  /** List of avatars to stack. Order = render order (left to right). */
  items: BTAvatarItem[];
  /** Maximum visible avatars before overflow counter appears. Defaults to `3`. */
  max?: number;
  /** Override the overflow number display (e.g. show "+99"). */
  customOverflowNumber?: number;
  /** Size applied uniformly to all avatars + overflow. Defaults to `md`. */
  size?: BTAvatarSize;
  /** When true, all positions render as skeleton placeholders. */
  isLoading?: boolean;
  /** Pass-through className for layout overrides. */
  className?: string;
}

// Public barrel for the BTAvatarGroup organism.
export { BTAvatarGroup } from './BTAvatarGroup';
export type { BTAvatarGroupProps } from './BTAvatarGroup.types';
